sql:
SELECT AVG(income) AS average_income
FROM census_data
WHERE neighborhood_id = 0 AND year = 2022;

SELECT AVG(population_density) AS average_density
FROM postal_codes
WHERE borough = 'Scarborough';

SELECT AVG(average_price) AS average_property_price
FROM real_estate_data
WHERE year = 2022;

SELECT neighborhood_id, average_price
FROM real_estate_data
WHERE year = 2022;

SELECT neighborhood_id, budget
FROM urban_plans
WHERE status = 'ongoing';

SELECT SUM(budget) AS total_budget
FROM urban_plans
WHERE status = 'ongoing';

SELECT AVG(population_density) AS average_population_density
FROM postal_codes
WHERE borough = 'Scarborough';

SELECT borough_name 
FROM boroughs 
ORDER BY borough_name;

external_knowledge:
- "Ongoing urban development projects" refers to urban plans with a status of 'ongoing'; 
- "Since last year" implies a comparison between 2022 and 2021; 
- "Property price increase of more than 10%" is calculated as (new price - old price) * 100 / old price.
